#pragma once
#include <stdint.h>
#include <stddef.h>
#include <math.h>
namespace hud {
enum class PidFormula:uint8_t{Unsupported,A,Percent,Coolant,Rpm,Timing,AirFlow,Throttle,Runtime,Distance,FuelPressure,IntakePressure,Temperature,Voltage,FuelRate,Torque,Ratio};
struct PidDef{uint8_t pid;const char*name;const char*unit;float minimum,maximum;uint8_t bytes;PidFormula formula;};
static constexpr PidDef SAE_PIDS[]={
{0x00,"PIDs supported 01-20","bitset",0,0,4,PidFormula::Unsupported},{0x01,"Monitor status since DTC clear","bitset",0,0,4,PidFormula::Unsupported},{0x02,"Freeze DTC","DTC",0,0,2,PidFormula::Unsupported},{0x03,"Fuel system status","bitset",0,0,2,PidFormula::Unsupported},{0x04,"Calculated engine load","%",0,100,1,PidFormula::Percent},{0x05,"Engine coolant temperature","C",-40,215,1,PidFormula::Coolant},{0x06,"Short term fuel trim bank 1","%",-100,99.2,1,PidFormula::Ratio},{0x07,"Long term fuel trim bank 1","%",-100,99.2,1,PidFormula::Ratio},{0x08,"Short term fuel trim bank 2","%",-100,99.2,1,PidFormula::Ratio},{0x09,"Long term fuel trim bank 2","%",-100,99.2,1,PidFormula::Ratio},{0x0A,"Fuel pressure","kPa",0,765,1,PidFormula::FuelPressure},{0x0B,"Intake manifold pressure","kPa",0,255,1,PidFormula::IntakePressure},{0x0C,"Engine speed","rpm",0,16383.75,2,PidFormula::Rpm},{0x0D,"Vehicle speed","km/h",0,255,1,PidFormula::A},{0x0E,"Timing advance","deg",-64,63.5,1,PidFormula::Timing},{0x0F,"Intake air temperature","C",-40,215,1,PidFormula::Temperature},{0x10,"MAF air flow","g/s",0,655.35,2,PidFormula::AirFlow},{0x11,"Throttle position","%",0,100,1,PidFormula::Throttle},{0x12,"Commanded secondary air status","enum",0,0,1,PidFormula::Unsupported},{0x13,"Oxygen sensors present","bitset",0,0,1,PidFormula::Unsupported},{0x1C,"OBD standard","enum",0,0,1,PidFormula::Unsupported},{0x1F,"Run time since engine start","s",0,65535,2,PidFormula::Runtime},{0x20,"PIDs supported 21-40","bitset",0,0,4,PidFormula::Unsupported},{0x21,"Distance with MIL on","km",0,65535,2,PidFormula::Distance},{0x2F,"Fuel tank input level","%",0,100,1,PidFormula::Percent},{0x30,"Warm-ups since DTC clear","count",0,255,1,PidFormula::A},{0x31,"Distance since DTC clear","km",0,65535,2,PidFormula::Distance},{0x33,"Absolute barometric pressure","kPa",0,255,1,PidFormula::A},{0x40,"PIDs supported 41-60","bitset",0,0,4,PidFormula::Unsupported},{0x42,"Control module voltage","V",0,65.535,2,PidFormula::Voltage},{0x45,"Relative throttle position","%",0,100,1,PidFormula::Percent},{0x46,"Ambient air temperature","C",-40,215,1,PidFormula::Temperature},{0x4C,"Commanded throttle actuator","%",0,100,1,PidFormula::Percent},{0x4D,"Time run with MIL on","min",0,65535,2,PidFormula::Runtime},{0x4E,"Time since trouble codes cleared","min",0,65535,2,PidFormula::Runtime},{0x51,"Fuel type","enum",0,0,1,PidFormula::Unsupported},{0x52,"Ethanol fuel percentage","%",0,100,1,PidFormula::Percent},{0x5C,"Engine oil temperature","C",-40,210,1,PidFormula::Temperature},{0x5E,"Engine fuel rate","L/h",0,3212.75,2,PidFormula::FuelRate},{0x60,"PIDs supported 61-80","bitset",0,0,4,PidFormula::Unsupported},{0x61,"Driver demanded torque","%",-125,125,1,PidFormula::Torque},{0x62,"Actual engine torque","%",-125,125,1,PidFormula::Torque},{0x63,"Engine reference torque","Nm",0,65535,2,PidFormula::Distance},{0x7F,"Engine run time","s",0,4294967295.0f,4,PidFormula::Unsupported},{0x80,"PIDs supported 81-A0","bitset",0,0,4,PidFormula::Unsupported},{0xA0,"PIDs supported A1-C0","bitset",0,0,4,PidFormula::Unsupported},{0xA6,"Odometer","km",0,429496729.5f,4,PidFormula::Unsupported}};
inline const PidDef* findPid(uint8_t pid){for(const auto&d:SAE_PIDS)if(d.pid==pid)return &d;return nullptr;}
inline bool decodePidValue(const PidDef&d,const uint8_t*p,size_t n,float&v){if(n<d.bytes)return false;uint32_t ab=n>1?((uint32_t)p[0]<<8)|p[1]:p[0];switch(d.formula){case PidFormula::A:v=p[0];break;case PidFormula::Percent:case PidFormula::Throttle:v=p[0]*100.0f/255;break;case PidFormula::Coolant:case PidFormula::Temperature:v=(int)p[0]-40;break;case PidFormula::Rpm:v=ab/4.0f;break;case PidFormula::Timing:v=p[0]/2.0f-64;break;case PidFormula::AirFlow:v=ab/100.0f;break;case PidFormula::Runtime:case PidFormula::Distance:v=ab;break;case PidFormula::FuelPressure:v=p[0]*3.0f;break;case PidFormula::IntakePressure:v=p[0];break;case PidFormula::Voltage:v=ab/1000.0f;break;case PidFormula::FuelRate:v=ab/20.0f;break;case PidFormula::Torque:v=(int)p[0]-125;break;case PidFormula::Ratio:v=p[0]*100.0f/128-100;break;default:return false;}return isfinite(v);}
}
